patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..236eeb4ba755 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1784,6 +1784,31 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     return replaceInstUsesWith(I, UMax);
   }

+  // Fold unsigned ceil division by a power-of-2:
+  // (X >>u ShAmt) + zext((X & ((1 << ShAmt) - 1)) != 0) --> (X + Mask) >>u ShAmt
+  // This is the canonical form of udiv ceil for a power-of-2 divisor.
+  {
+    Value *X;
+    const APInt *ShAmtC, *MaskC;
+    if (match(LHS, m_OneUse(m_LShr(m_Value(X), m_APInt(ShAmtC)))) &&
+        match(RHS, m_ZExt(m_OneUse(m_SpecificICmp(
+                       ICmpInst::ICMP_NE,
+                       m_OneUse(m_And(m_Specific(X), m_APInt(MaskC))),
+                       m_ZeroInt())))) &&
+        MaskC->isMask() && ShAmtC->ult(MaskC->getBitWidth()) &&
+        MaskC->countr_one() == ShAmtC->getZExtValue()) {
+      KnownBits XKnown = computeKnownBits(X, &I);
+      if (XKnown.countMinLeadingZeros() >= ShAmtC->getZExtValue() &&
+          XKnown.getMaxValue().ule(~*MaskC)) {
+        Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(I.getType(), *MaskC),
+                                          "", /*HasNUW=*/true,
+                                          /*HasNSW=*/I.hasNoSignedWrap());
+        return BinaryOperator::CreateLShr(
+            NewAdd, ConstantInt::get(I.getType(), *ShAmtC));
+      }
+    }
+  }
+
   if (Instruction *Ashr = foldAddToAshr(I))
     return Ashr;

